+import {Options, RuleType} from '../rules';
+import RuleBuilder, {ExampleBuilder, OptionBuilderBase} from './rule-builder';
+import dedent from 'ts-dedent';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {level: number, text: string};
+
+const startMarker = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const endMarker = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const atxHeading = /^(?: {0,3})(#{1,6})(?:[ \	]+)(.*)$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.HEADING,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const lines = text.split('\
');
+    const start = lines.findIndex((line) => startMarker.test(line));
+    if (start === -1) {
+      return text;
+    }
+
+    let end = -1;
+    for (let index = start + 1; index < lines.length; index++) {
+      if (endMarker.test(lines[index])) {
+        end = index;
+        break;
+      }
+    }
+
+    const regionEnd = end === -1 ? lines.length : end + 1;
+    const headings = getHeadings(lines, start, regionEnd, options)
+        .filter((heading) => !isExcluded(heading.text, options.excludeHeadings));
+    const toc = buildToc(headings, options);
+    const generated = [lines[start], '', ...(options.title === '' ? [] : [options.title, '']), ...toc, '', '<!-- /toc -->', ''];
+
+    return [...lines.slice(0, start), ...generated, ...lines.slice(regionEnd)].join('\
');
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Generates a table of contents when opted in with a TOC marker',
+        before: dedent`
+          <!-- toc -->
+
+          ## First section
+          ### Nested section
+        `,
+        after: dedent`
+          <!-- toc -->
+
+          - [First section](#first-section)
+            - [Nested section](#nested-section)
+
+          <!-- /toc -->
+
+          ## First section
+          ### Nested section
+        `,
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    // These options intentionally have no settings controls yet. They are supported
+    // by the rule API and custom rule configuration.
+    return [];
+  }
+}
+
+function getHeadings(lines: string[], tocStart: number, tocEnd: number, options: AutoTocOptions): Heading[] {
+  const headings: Heading[] = [];
+  let inYaml = lines[0]?.trim() === '---';
+  let fence: string | null = null;
+  let inMath = false;
+
+  for (let index = 0; index < lines.length; index++) {
+    const line = lines[index];
+    if (index >= tocStart && index < tocEnd) {
+      continue;
+    }
+
+    if (inYaml) {
+      if (index > 0 && /^(---|\\.\\.\\.)\\s*$/.test(line)) {
+        inYaml = false;
+      }
+      continue;
+    }
+
+    const fenceMatch = /^(?: {0,3})(`{3,}|~{3,})/.exec(line);
+    if (fence) {
+      if (fenceMatch && fenceMatch[1][0] === fence[0] && fenceMatch[1].length >= fence.length) {
+        fence = null;
+      }
+      continue;
+    }
+    if (fenceMatch) {
+      fence = fenceMatch[1];
+      continue;
+    }
+
+    if (/^\\s*\\$\\$\\s*$/.test(line)) {
+      inMath = !inMath;
+      continue;
+    }
+    if (inMath) {
+      continue;
+    }
+
+    const match = atxHeading.exec(line);
+    if (!match || match[1].length < options.minLevel || match[1].length > options.maxLevel) {
+      continue;
+    }
+    headings.push({level: match[1].length, text: cleanHeadingText(match[2])});
+  }
+  return headings;
+}
+
+function cleanHeadingText(text: string): string {
+  return text.trim().replace(/[ \	]+#+[ \	]*$/, '').trim();
+}
+
+function buildToc(headings: Heading[], options: AutoTocOptions): string[] {
+  const anchors = new Map<string, number>();
+  return headings.map((heading, index) => {
+    const explicitId = options.useExplicitIds ? /\\s*\\{#([^}]+)\\}\\s*$/.exec(heading.text)?.[1] : undefined;
+    const text = heading.text.replace(/\\s*\\{#[^}]+\\}\\s*$/, '').trim();
+    const displayText = resolveLinks(text);
+    const anchorBase = anchorize(explicitId ?? displayText);
+    const count = anchors.get(anchorBase) ?? 0;
+    anchors.set(anchorBase, count + 1);
+    const anchor = count === 0 ? anchorBase : `${anchorBase}-${count}`;
+    const label = options.stripFormattingInToc ? stripFormatting(displayText) : displayText;
+    const indent = ' '.repeat(Math.max(0, heading.level - options.minLevel) * Math.max(0, options.indentSize));
+    const marker = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` : options.bulletMarker;
+    return `${indent}${marker} [${label}](#${anchor})`;
+  });
+}
+
+function resolveLinks(text: string): string {
+  return text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)(?:\\|([^\\]]+))?\\]\\]/g, (_match, target: string, display?: string) => display ?? target)
+      .replace(/\\[([^\\]]*)\\]\\([^)]*\\)/g, '$1');
+}
+
+function stripFormatting(text: string): string {
+  return text
+      .replace(/`([^`]*)`/g, '$1')
+      .replace(/(\\*\\*|__|~~)(.*?)\\1/g, '$2')
+      .replace(/(?<!\\w)[*_]([^*_]+)[*_](?!\\w)/g, '$1');
+}
+
+function anchorize(text: string): string {
+  return stripFormatting(resolveLinks(text))
+      .replace(/[ \	]+#+[ \	]*$/, '')
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9_-]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+}
+
+function isExcluded(text: string, exclusions: string[]): boolean {
+  const candidate = text.trim();
+  return exclusions.some((exclusion) => {
+    const regex = /^\\/(.*)\\/$/.exec(exclusion);
+    if (regex) {
+      try {
+        return new RegExp(regex[1], 'i').test(candidate);
+      } catch (_error) {
+        return candidate.toLocaleLowerCase() === exclusion.toLocaleLowerCase();
+      }
+    }
+    return candidate.toLocaleLowerCase() === exclusion.toLocaleLowerCase();
+  });
+}
